def election_winner(votes):
    counts = {}
    for vote in votes:
        counts[vote] = counts.get(vote, 0) + 1
    max_count = max(counts.values())
    winners = [name for name, c in counts.items() if c == max_count]
    return min(winners)

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_clear_winner(self):
        self.assertEqual(election_winner(["Alice", "Bob", "Alice", "Charlie", "Alice"]), "Alice")

    def test_tie_alphabetical(self):
        self.assertEqual(election_winner(["Bob", "Alice", "Bob", "Alice"]), "Alice")

    def test_single_vote(self):
        self.assertEqual(election_winner(["Zara"]), "Zara")

    def test_hidden_all_same(self):
        self.assertEqual(election_winner(["Bob", "Bob", "Bob"]), "Bob")

    def test_hidden_three_way_tie(self):
        self.assertEqual(election_winner(["Dana", "Eve", "Frank", "Dana", "Eve", "Frank"]), "Dana")

    def test_hidden_all_unique(self):
        self.assertEqual(election_winner(["X", "Y", "Z"]), "X")

    def test_hidden_large_margin(self):
        self.assertEqual(election_winner(["Charlie", "Bob", "Alice", "Charlie", "Bob", "Alice", "Charlie"]), "Charlie")

    def test_hidden_two_candidates_one_wins(self):
        self.assertEqual(election_winner(["Eve", "Eve", "Frank"]), "Eve")

if __name__ == '__main__':
    unittest.main()
